// Time:  O(n + m)
// Space: O(n)

// hash table
class Solution {
public:
    int minimumSum(vector<int>& nums1, vector<int>& nums2) {
        static const int INF = numeric_limits<int>::max();

        unordered_map<int, int> lookup;
        for (int i = 0; i < size(nums1); ++i) {
            if (lookup.count(nums1[i])) {
                continue;
            }
            lookup[nums1[i]] = i;
        }
        int result = INF;
        for (int j = 0; j < size(nums2); ++j) {
            if (lookup.count(nums2[j])) {
                result = min(result, lookup[nums2[j]] + j);
            }
        }
        return result != INF ? result : -1;
    }
};

# Time:  O(n + m)
# Space: O(n)

# hash table
class Solution(object):
    def minimumSum(self, nums1, nums2):
        """
        :type nums1: List[int]
        :type nums2: List[int]
        :rtype: int
        """
        INF = float("inf")
        lookup = {}
        for i, x in enumerate(nums1):
            if x in lookup:
                continue
            lookup[x] = i
        result = INF
        for j, x in enumerate(nums2):
            if x in lookup:
                result = min(result, lookup[x]+j)
        return result if result != INF else -1
